  1→import { ORPCError } from "@orpc/server";
  2→import { getAdapter } from "@rudel/agent-adapters";
  3→import { apikey, member, organization, session } from "@rudel/sql-schema";
  4→import { and, eq } from "drizzle-orm";
  5→import { getClickhouse } from "./clickhouse.js";
  6→import { db } from "./db.js";
  7→import { analyticsRouter } from "./handlers/analytics/index.js";
  8→import { authMiddleware, ingestAuthMiddleware, os } from "./middleware.js";
  9→import { checkIngestRateLimit } from "./rate-limit.js";
 10→import {
 11→	deleteOrgSessions,
 12→	getOrgSessionCount,
 13→} from "./services/org-session.service.js";
 14→
 15→const health = os.health.handler(() => {
 16→	return {
 17→		status: "ok" as const,
 18→		timestamp: Date.now(),
 19→	};
 20→});
 21→
 22→const me = os.me.use(authMiddleware).handler(({ context }) => {
 23→	return {
 24→		id: context.user.id,
 25→		email: context.user.email,
 26→		name: context.user.name,
 27→		image: context.user.image ?? null,
 28→		activeOrganizationId:
 29→			((context.session as Record<string, unknown>).activeOrganizationId as
 30→				| string
 31→				| null) ?? null,
 32→	};
 33→});
 34→
 35→const cliAuthStatus = os.cli.authStatus
 36→	.use(ingestAuthMiddleware)
 37→	.handler(({ context }) => {
 38→		return {
 39→			id: context.user.id,
 40→			email: context.user.email,
 41→			name: context.user.name,
 42→		};
 43→	});
 44→
 45→const listMyOrganizations = os.listMyOrganizations
 46→	.use(authMiddleware)
 47→	.handler(async ({ context }) => {
 48→		const memberships = await db
 49→			.select({
 50→				id: organization.id,
 51→				name: organization.name,
 52→				slug: organization.slug,
 53→				logo: organization.logo,
 54→			})
 55→			.from(member)
 56→			.innerJoin(organization, eq(member.organizationId, organization.id))
 57→			.where(eq(member.userId, context.user.id));
 58→
 59→		return memberships.map((m) => ({
 60→			id: m.id,
 61→			name: m.name,
 62→			slug: m.slug,
 63→			logo: m.logo ?? null,
 64→		}));
 65→	});
 66→
 67→const ingestSessionHandler = os.ingestSession
 68→	.use(ingestAuthMiddleware)
 69→	.handler(async ({ input, context }) => {
 70→		const activeOrgId =
 71→			context.session &&
 72→			typeof (context.session as Record<string, unknown>)
 73→				.activeOrganizationId === "string"
 74→				? ((context.session as Record<string, unknown>)
 75→						.activeOrganizationId as string)
 76→				: null;
 77→
 78→		await checkIngestRateLimit(context.user.id);
 79→
 80→		const orgId = input.organizationId ?? activeOrgId ?? context.user.id;
 81→
 82→		// Verify membership for any org that isn't the user's personal workspace
 83→		if (orgId !== context.user.id) {
 84→			const membership = await db
 85→				.select({ id: member.id })
 86→				.from(member)
 87→				.where(
 88→					and(
 89→						eq(member.organizationId, orgId),
 90→						eq(member.userId, context.user.id),
 91→					),
 92→				)
 93→				.limit(1);
 94→
 95→			if (membership.length === 0) {
 96→				throw new ORPCError("FORBIDDEN", {
 97→					message: "Not a member of the specified organization",
 98→				});
 99→			}
100→		}
101→
102→		const adapter = getAdapter(input.source);
103→		await adapter.ingest(getClickhouse(), input, {
104→			userId: context.user.id,
105→			organizationId: orgId,
106→		});
107→
108→		return {
109→			success: true as const,
110→			sessionId: input.sessionId,
111→		};
112→	});
113→
114→const revokeCliToken = os.cli.revokeToken
115→	.use(ingestAuthMiddleware)
116→	.handler(async ({ context }) => {
117→		if (!context.apiKeyId) {
118→			throw new ORPCError("BAD_REQUEST", {
119→				message: "No API key in current authentication context",
120→			});
121→		}
122→
123→		await db
124→			.update(apikey)
125→			.set({ enabled: false, updatedAt: new Date() })
126→			.where(
127→				and(
128→					eq(apikey.id, context.apiKeyId),
129→					eq(apikey.referenceId, context.user.id),
130→				),
131→			);
132→
133→		return { success: true as const };
134→	});
135→
136→const getOrganizationSessionCount = os.getOrganizationSessionCount
137→	.use(authMiddleware)
138→	.handler(async ({ input, context }) => {
139→		const membership = await db
140→			.select({ id: member.id })
141→			.from(member)
142→			.where(
143→				and(
144→					eq(member.organizationId, input.organizationId),
145→					eq(member.userId, context.user.id),
146→				),
147→			)
148→			.limit(1);
149→
150→		if (membership.length === 0) {
151→			throw new ORPCError("FORBIDDEN", {
152→				message: "Not a member of this organization",
153→			});
154→		}
155→
156→		const count = await getOrgSessionCount(input.organizationId);
157→		return { count };
158→	});
159→
160→const deleteOrganization = os.deleteOrganization
161→	.use(authMiddleware)
162→	.handler(async ({ input, context }) => {
163→		const orgId = input.organizationId;
164→		const userId = context.user.id;
165→		console.log(`[deleteOrganization] user=${userId} org=${orgId}`);
166→
167→		// Check user has more than one org
168→		const memberships = await db
169→			.select({ organizationId: member.organizationId })
170→			.from(member)
171→			.where(eq(member.userId, userId));
172→
173→		if (memberships.length <= 1) {
174→			console.log(
175→				`[deleteOrganization] rejected: user=${userId} has only ${memberships.length} org(s)`,
176→			);
177→			throw new ORPCError("BAD_REQUEST", {
178→				message: "Cannot delete your only organization",
179→			});
180→		}
181→
182→		// Verify user is owner of the target org
183→		const ownership = await db
184→			.select({ id: member.id })
185→			.from(member)
186→			.where(
187→				and(
188→					eq(member.organizationId, orgId),
189→					eq(member.userId, userId),
190→					eq(member.role, "owner"),
191→				),
192→			)
193→			.limit(1);
194→
195→		if (ownership.length === 0) {
196→			console.log(
197→				`[deleteOrganization] rejected: user=${userId} is not owner of org=${orgId}`,
198→			);
199→			throw new ORPCError("FORBIDDEN", {
200→				message: "Only the organization owner can delete it",
201→			});
202→		}
203→
204→		try {
205→			// Fire-and-forget: ClickHouse mutations are slow, don't block on them
206→			deleteOrgSessions(orgId);
207→
208→			// Delete the organization from Postgres (cascade handles member + invitation)
209→			console.log(`[deleteOrganization] deleting org=${orgId} from Postgres`);
210→			await db.delete(organization).where(eq(organization.id, orgId));
211→
212→			// Clear activeOrganizationId on user sessions that reference the deleted org
213→			console.log(
214→				`[deleteOrganization] clearing activeOrganizationId references for org=${orgId}`,
215→			);
216→			await db
217→				.update(session)
218→				.set({ activeOrganizationId: null })
219→				.where(eq(session.activeOrganizationId, orgId));
220→
221→			console.log(`[deleteOrganization] success for org=${orgId}`);
222→			return { success: true as const };
223→		} catch (error) {
224→			if (error instanceof ORPCError) throw error;
225→			console.error(`[deleteOrganization] failed for org=${orgId}:`, error);
226→			throw error;
227→		}
228→	});
229→
230→export const router = os.router({
231→	health,
232→	me,
233→	cli: {
234→		authStatus: cliAuthStatus,
235→		revokeToken: revokeCliToken,
236→	},
237→	listMyOrganizations,
238→	ingestSession: ingestSessionHandler,
239→	getOrganizationSessionCount,
240→	deleteOrganization,
241→	analytics: analyticsRouter,
242→});
