 1→import { implement, ORPCError } from "@orpc/server";
 2→import { contract } from "@rudel/api-routes";
 3→import { member } from "@rudel/sql-schema";
 4→import { and, eq } from "drizzle-orm";
 5→import type { Session } from "./auth.js";
 6→import { db } from "./db.js";
 7→
 8→export interface AppContext {
 9→	user: Session["user"] | null;
10→	session: Session["session"] | null;
11→	apiKeyId: string | null;
12→}
13→
14→export const os = implement(contract).$context<AppContext>();
15→
16→export const authMiddleware = os.middleware(async ({ context, next }) => {
17→	if (!context.user || !context.session) {
18→		throw new ORPCError("UNAUTHORIZED");
19→	}
20→	return next({
21→		context: {
22→			user: context.user,
23→			session: context.session,
24→			apiKeyId: context.apiKeyId,
25→		},
26→	});
27→});
28→
29→export const orgMiddleware = os.middleware(async ({ context, next }) => {
30→	if (!context.user || !context.session) {
31→		throw new ORPCError("UNAUTHORIZED");
32→	}
33→	const organizationId =
34→		(context.session as Record<string, unknown>).activeOrganizationId ??
35→		context.user.id;
36→	if (!organizationId || typeof organizationId !== "string") {
37→		throw new ORPCError("BAD_REQUEST", {
38→			message: "No active organization",
39→		});
40→	}
41→
42→	const membership = await db
43→		.select({ id: member.id, role: member.role })
44→		.from(member)
45→		.where(
46→			and(
47→				eq(member.organizationId, organizationId),
48→				eq(member.userId, context.user.id),
49→			),
50→		)
51→		.limit(1);
52→
53→	const row = membership[0];
54→	if (!row) {
55→		throw new ORPCError("FORBIDDEN", {
56→			message: "Not a member of the active organization",
57→		});
58→	}
59→
60→	const userRole = (row.role as "owner" | "admin" | "member") ?? "member";
61→	const isOrgAdmin = userRole === "owner" || userRole === "admin";
62→
63→	return next({
64→		context: {
65→			user: context.user,
66→			session: context.session,
67→			apiKeyId: context.apiKeyId,
68→			organizationId,
69→			userRole,
70→			isOrgAdmin,
71→		},
72→	});
73→});
74→
75→export const ingestAuthMiddleware = os.middleware(async ({ context, next }) => {
76→	if (!context.user) {
77→		throw new ORPCError("UNAUTHORIZED");
78→	}
79→
80→	if (!context.session && !context.apiKeyId) {
81→		throw new ORPCError("UNAUTHORIZED");
82→	}
83→
84→	return next({
85→		context: {
86→			user: context.user,
87→			session: context.session,
88→			apiKeyId: context.apiKeyId,
89→		},
90→	});
91→});
