 1→import { useQuery, useQueryClient } from "@tanstack/react-query";
 2→import { useCallback } from "react";
 3→import { authClient } from "../lib/auth-client";
 4→
 5→export const USER_INVITATIONS_KEY = ["user-invitations"] as const;
 6→
 7→export function useUserInvitations() {
 8→	const queryClient = useQueryClient();
 9→
10→	const { data, isLoading } = useQuery({
11→		queryKey: USER_INVITATIONS_KEY,
12→		queryFn: async () => {
13→			const res = await authClient.organization.listUserInvitations();
14→			return res.data ?? [];
15→		},
16→	});
17→
18→	const invitations = data ?? [];
19→
20→	const invalidate = useCallback(() => {
21→		queryClient.invalidateQueries({ queryKey: USER_INVITATIONS_KEY });
22→	}, [queryClient]);
23→
24→	return { invitations, count: invitations.length, isLoading, invalidate };
25→}
