 1→import { useOrganization } from "@/contexts/OrganizationContext";
 2→import { authClient } from "@/lib/auth-client";
 3→
 4→/**
 5→ * Returns whether the current user can view a specific session's details.
 6→ * Admins/owners can view all sessions; regular members can only view their own.
 7→ */
 8→export function useCanViewSession() {
 9→	const { isOrgAdmin } = useOrganization();
10→	const { data: session } = authClient.useSession();
11→	const currentUserId = session?.user.id;
12→
13→	return (sessionUserId: string) => {
14→		if (isOrgAdmin) return true;
15→		return currentUserId === sessionUserId;
16→	};
17→}
