  1→import { Building2, Check, Loader2, Mail, X } from "lucide-react";
  2→import { useState } from "react";
  3→import { AnalyticsCard } from "@/components/analytics/AnalyticsCard";
  4→import { PageHeader } from "@/components/analytics/PageHeader";
  5→import { Button } from "@/components/ui/button";
  6→import { useOrganization } from "@/contexts/OrganizationContext";
  7→import { useUserInvitations } from "@/hooks/useUserInvitations";
  8→import { authClient } from "@/lib/auth-client";
  9→
 10→export function InvitationsPage() {
 11→	const { invitations, isLoading, invalidate } = useUserInvitations();
 12→	const { switchOrg } = useOrganization();
 13→	const [processingId, setProcessingId] = useState<string | null>(null);
 14→
 15→	const handleAccept = async (invitationId: string) => {
 16→		setProcessingId(invitationId);
 17→		const res = await authClient.organization.acceptInvitation({
 18→			invitationId,
 19→		});
 20→		if (res.data) {
 21→			await switchOrg(res.data.member.organizationId);
 22→		}
 23→		invalidate();
 24→		setProcessingId(null);
 25→	};
 26→
 27→	const handleDecline = async (invitationId: string) => {
 28→		setProcessingId(invitationId);
 29→		await authClient.organization.rejectInvitation({ invitationId });
 30→		invalidate();
 31→		setProcessingId(null);
 32→	};
 33→
 34→	if (isLoading) {
 35→		return (
 36→			<div className="px-8 py-6">
 37→				<PageHeader
 38→					title="Invitations"
 39→					description="Pending invitations to join organizations"
 40→				/>
 41→				<AnalyticsCard>
 42→					<div className="flex items-center justify-center py-12 text-muted gap-2">
 43→						<Loader2 className="h-4 w-4 animate-spin" />
 44→						<span>Loading invitations...</span>
 45→					</div>
 46→				</AnalyticsCard>
 47→			</div>
 48→		);
 49→	}
 50→
 51→	return (
 52→		<div className="px-8 py-6">
 53→			<PageHeader
 54→				title="Invitations"
 55→				description="Pending invitations to join organizations"
 56→			/>
 57→
 58→			{invitations.length === 0 ? (
 59→				<AnalyticsCard>
 60→					<div className="text-center py-12">
 61→						<div className="mx-auto mb-4 flex h-12 w-12 items-center justify-center rounded-full bg-hover">
 62→							<Mail className="h-6 w-6 text-muted" />
 63→						</div>
 64→						<p className="text-lg font-medium text-foreground mb-1">
 65→							No pending invitations
 66→						</p>
 67→						<p className="text-sm text-muted">
 68→							When someone invites you to an organization, it will appear here.
 69→						</p>
 70→					</div>
 71→				</AnalyticsCard>
 72→			) : (
 73→				<div className="space-y-4">
 74→					{invitations.map((invitation) => {
 75→						const isProcessing = processingId === invitation.id;
 76→						return (
 77→							<AnalyticsCard key={invitation.id}>
 78→								<div className="flex items-center justify-between">
 79→									<div className="flex items-center gap-4">
 80→										<div className="flex h-10 w-10 items-center justify-center rounded-full bg-hover">
 81→											<Building2 className="h-5 w-5 text-accent" />
 82→										</div>
 83→										<div>
 84→											<p className="text-sm font-semibold text-heading">
 85→												{invitation.organizationName}
 86→											</p>
 87→											<div className="flex items-center gap-2 mt-0.5">
 88→												<span className="inline-flex items-center rounded-full bg-hover px-2 py-0.5 text-xs font-medium text-subheading">
 89→													{invitation.role}
 90→												</span>
 91→												<span className="text-xs text-muted">
 92→													Invited{" "}
 93→													{new Date(invitation.createdAt).toLocaleDateString()}
 94→												</span>
 95→											</div>
 96→										</div>
 97→									</div>
 98→									<div className="flex items-center gap-2">
 99→										<Button
100→											variant="outline"
101→											size="sm"
102→											onClick={() => handleDecline(invitation.id)}
103→											disabled={isProcessing}
104→										>
105→											{isProcessing ? (
106→												<Loader2 className="h-4 w-4 mr-1 animate-spin" />
107→											) : (
108→												<X className="h-4 w-4 mr-1" />
109→											)}
110→											Decline
111→										</Button>
112→										<Button
113→											size="sm"
114→											onClick={() => handleAccept(invitation.id)}
115→											disabled={isProcessing}
116→										>
117→											{isProcessing ? (
118→												<Loader2 className="h-4 w-4 mr-1 animate-spin" />
119→											) : (
120→												<Check className="h-4 w-4 mr-1" />
121→											)}
122→											Accept
123→										</Button>
124→									</div>
125→								</div>
126→							</AnalyticsCard>
127→						);
128→					})}
129→				</div>
130→			)}
131→		</div>
