 24→	Select,
 25→	SelectContent,
 26→	SelectItem,
 27→	SelectTrigger,
 28→	SelectValue,
 29→} from "../../components/ui/select";
 30→import { useOrganization } from "../../contexts/OrganizationContext";
 31→import { useFullOrganization } from "../../hooks/useFullOrganization";
 32→import { authClient } from "../../lib/auth-client";
 33→
 34→export function OrganizationPage() {
 35→	const { activeOrg, organizations, switchOrg } = useOrganization();
 36→	const { data: session } = authClient.useSession();
 37→	const navigate = useNavigate();
 38→	const {
 39→		data: fullOrg,
 40→		isLoading: loading,
 41→		invalidate,
 42→	} = useFullOrganization(activeOrg?.id);
 43→	const [inviteEmail, setInviteEmail] = useState("");
 44→	const [inviteRole, setInviteRole] = useState("member");
 45→	const [inviting, setInviting] = useState(false);
 46→	const [inviteLink, setInviteLink] = useState<string | null>(null);
 47→	const [invitedEmail, setInvitedEmail] = useState<string | null>(null);
 48→	const [copied, setCopied] = useState(false);
 49→	const [deleteDialogOpen, setDeleteDialogOpen] = useState(false);
 50→	const [editing, setEditing] = useState(false);
 51→	const [editName, setEditName] = useState("");
 52→	const [saving, setSaving] = useState(false);
 53→	const [renameError, setRenameError] = useState<string | null>(null);
 54→	const nameInputRef = useRef<HTMLInputElement>(null);
 55→
 56→	const currentUserRole = fullOrg?.members.find(
 57→		(m) => m.userId === session?.user.id,
 58→	)?.role;
 59→	const canEdit = currentUserRole === "owner" || currentUserRole === "admin";
 60→
 61→	const handleStartEditing = () => {
 62→		if (!activeOrg) return;
 63→		setEditName(activeOrg.name);
 64→		setRenameError(null);
 65→		setEditing(true);
 66→		setTimeout(() => nameInputRef.current?.focus(), 0);
 67→	};
 68→
 69→	const handleCancelEditing = () => {
 70→		setEditing(false);
 71→		setRenameError(null);
 72→	};
 73→
 74→	const handleSaveName = async () => {
 75→		const trimmed = editName.trim();
 76→		if (!trimmed || !activeOrg) return;
 77→		if (trimmed === activeOrg.name) {
 78→			setEditing(false);
 79→			return;
 80→		}
 81→
 82→		setSaving(true);
 83→		setRenameError(null);
 84→		const res = await authClient.organization.update({
 85→			data: { name: trimmed },
 86→			organizationId: activeOrg.id,
 87→		});
 88→
 89→		if (res.error) {
 90→			setRenameError(res.error.message ?? "Failed to rename organization");
 91→			setSaving(false);
 92→			return;
 93→		}
 94→
 95→		setEditing(false);
 96→		setSaving(false);
 97→		invalidate();
 98→	};
 99→
100→	const handleInvite = async (e: React.FormEvent) => {
101→		e.preventDefault();
102→		if (!inviteEmail.trim()) return;
103→		setInviting(true);
104→		const email = inviteEmail.trim();
105→		const res = await authClient.organization.inviteMember({
106→			email,
107→			role: inviteRole as "member" | "admin",
108→		});
109→		if (res.data) {
110→			const link = `${window.location.origin}/invitation/${res.data.id}`;
111→			setInviteLink(link);
112→			setInvitedEmail(email);
113→			setInviteEmail("");
114→			invalidate();
115→		}
116→		setInviting(false);
117→	};
118→
119→	const handleCopyLink = () => {
120→		if (!inviteLink) return;
121→		navigator.clipboard.writeText(inviteLink);
122→		setCopied(true);
123→		setTimeout(() => setCopied(false), 2000);
124→	};
125→
126→	const handleRemoveMember = async (memberIdOrEmail: string) => {
127→		await authClient.organization.removeMember({ memberIdOrEmail });
128→		invalidate();
129→	};
130→
131→	const handleCancelInvitation = async (invitationId: string) => {
132→		await authClient.organization.cancelInvitation({ invitationId });
133→		invalidate();
134→	};
135→
136→	if (!activeOrg) {
137→		return (
138→			<div className="px-8 py-6">
139→				<p className="text-muted">No organization selected.</p>
