  1→import { useQueryClient } from "@tanstack/react-query";
  2→import { Building2, Check, Loader2, X } from "lucide-react";
  3→import { useEffect, useState } from "react";
  4→import { useNavigate, useParams } from "react-router-dom";
  5→import { Button } from "../components/ui/button";
  6→import { USER_INVITATIONS_KEY } from "../hooks/useUserInvitations";
  7→import { authClient } from "../lib/auth-client";
  8→
  9→export function AcceptInvitationPage() {
 10→	const { invitationId } = useParams<{ invitationId: string }>();
 11→	const navigate = useNavigate();
 12→	const queryClient = useQueryClient();
 13→	const { data: session, isPending: sessionLoading } = authClient.useSession();
 14→	const [status, setStatus] = useState<
 15→		"loading" | "accepting" | "accepted" | "error"
 16→	>("loading");
 17→	const [error, setError] = useState<string | null>(null);
 18→
 19→	useEffect(() => {
 20→		if (sessionLoading || !invitationId) return;
 21→
 22→		if (!session) {
 23→			const returnUrl = `/invitation/${invitationId}`;
 24→			window.location.href = `/?redirect=${encodeURIComponent(returnUrl)}`;
 25→			return;
 26→		}
 27→
 28→		setStatus("loading");
 29→	}, [session, sessionLoading, invitationId]);
 30→
 31→	const handleAccept = async () => {
 32→		if (!invitationId) return;
 33→		setStatus("accepting");
 34→		setError(null);
 35→
 36→		const res = await authClient.organization.acceptInvitation({
 37→			invitationId,
 38→		});
 39→
 40→		if (res.error) {
 41→			setError(res.error.message ?? "Failed to accept invitation");
 42→			setStatus("error");
 43→			return;
 44→		}
 45→
 46→		if (res.data) {
 47→			await authClient.organization.setActive({
 48→				organizationId: res.data.member.organizationId,
 49→			});
 50→		}
 51→
 52→		setStatus("accepted");
 53→		queryClient.invalidateQueries({ queryKey: USER_INVITATIONS_KEY });
 54→		setTimeout(() => navigate("/dashboard"), 1500);
 55→	};
 56→
 57→	const handleReject = async () => {
 58→		if (!invitationId) return;
 59→		await authClient.organization.rejectInvitation({ invitationId });
 60→		navigate("/dashboard");
 61→	};
 62→
 63→	if (sessionLoading) {
 64→		return (
 65→			<div className="flex min-h-screen items-center justify-center">
 66→				<Loader2 className="h-6 w-6 animate-spin text-muted" />
 67→			</div>
 68→		);
 69→	}
 70→
 71→	return (
 72→		<div className="flex min-h-screen items-center justify-center">
 73→			<div className="w-full max-w-sm rounded-xl border border-border bg-surface p-8 text-center">
 74→				<div className="mx-auto mb-4 flex h-12 w-12 items-center justify-center rounded-full bg-hover">
 75→					{status === "accepted" ? (
 76→						<Check className="h-6 w-6 text-status-success-icon" />
 77→					) : (
 78→						<Building2 className="h-6 w-6 text-accent" />
 79→					)}
 80→				</div>
 81→
 82→				{status === "accepted" ? (
 83→					<>
 84→						<h1 className="text-lg font-semibold text-heading mb-2">
 85→							Welcome to the team!
 86→						</h1>
 87→						<p className="text-sm text-muted">Redirecting to dashboard...</p>
 88→					</>
 89→				) : (
 90→					<>
 91→						<h1 className="text-lg font-semibold text-heading mb-2">
 92→							You've been invited
 93→						</h1>
 94→						<p className="text-sm text-muted mb-6">
 95→							Accept this invitation to join the organization.
 96→						</p>
 97→
 98→						{error && <p className="text-sm text-red-500 mb-4">{error}</p>}
 99→
100→						<div className="flex gap-3 justify-center">
101→							<Button
102→								variant="outline"
103→								size="sm"
104→								onClick={handleReject}
105→								disabled={status === "accepting"}
106→							>
107→								<X className="h-4 w-4 mr-1" />
108→								Decline
109→							</Button>
110→							<Button
111→								size="sm"
112→								onClick={handleAccept}
113→								disabled={status === "accepting"}
114→							>
115→								{status === "accepting" ? (
116→									<Loader2 className="h-4 w-4 mr-1 animate-spin" />
117→								) : (
118→									<Check className="h-4 w-4 mr-1" />
119→								)}
120→								Accept
121→							</Button>
122→						</div>
123→					</>
124→				)}
125→			</div>
126→		</div>
127→	);
128→}
