  2→import { getLogger } from "@logtape/logtape";
  3→import * as schema from "@rudel/sql-schema";
  4→import { betterAuth } from "better-auth";
  5→import { drizzleAdapter } from "better-auth/adapters/drizzle";
  6→import { bearer, deviceAuthorization, organization } from "better-auth/plugins";
  7→import { fetchGitHubHandle, notifySignup } from "./slack.js";
  8→
  9→const logger = getLogger(["rudel", "api", "auth"]);
 10→
 11→export interface AuthConfig {
 12→	appURL: string;
 13→	secret?: string;
 14→	socialProviders?: Record<string, { clientId: string; clientSecret: string }>;
 15→	trustedOrigins?: string[];
 16→	cliDeviceVerificationUrl?: string;
 17→	slackWebhookUrl?: string;
 18→}
 19→
 20→// eslint-disable-next-line @typescript-eslint/no-explicit-any -- drizzleAdapter accepts { [key: string]: any }
 21→export function createAuth(db: object, config: AuthConfig) {
 22→	const trustedOrigins = config.trustedOrigins ?? [];
 23→	if (!trustedOrigins.includes(config.appURL)) {
 24→		trustedOrigins.push(config.appURL);
 25→	}
 26→
 27→	return betterAuth({
 28→		baseURL: config.appURL,
 29→		secret: config.secret,
 30→		database: drizzleAdapter(db as Parameters<typeof drizzleAdapter>[0], {
 31→			provider: "pg",
 32→			schema,
 33→		}),
 34→		emailAndPassword: {
 35→			enabled: true,
 36→		},
 37→		socialProviders: config.socialProviders,
 38→		plugins: [
 39→			bearer(),
 40→			apiKey({
 41→				keyExpiration: {
 42→					defaultExpiresIn: null,
 43→				},
 44→				rateLimit: {
 45→					enabled: false,
 46→				},
 47→				permissions: {
 48→					defaultPermissions: {
 49→						ingest: ["write"],
 50→					},
 51→				},
 52→			}),
 53→			deviceAuthorization({
 54→				validateClient: async (clientId) => clientId === "rudel-cli",
 55→				verificationUri: config.cliDeviceVerificationUrl,
 56→			}),
 57→			organization({
 58→				allowUserToCreateOrganization: true,
 59→				creatorRole: "owner",
 60→				disableOrganizationDeletion: true,
 61→			}),
 62→		],
 63→		session: {
 64→			expiresIn: 60 * 60 * 24 * 365,
 65→		},
 66→		trustedOrigins,
 67→		databaseHooks: {
 68→			user: {
 69→				create: {
 70→					after: async (user, ctx) => {
 71→						try {
 72→							const adapter = ctx?.context?.adapter;
 73→							if (!adapter) return;
 74→
 75→							const slug = `${user.email.split("@")[0]}-${user.id.slice(0, 8)}`;
 76→							const org = await adapter.create({
 77→								model: "organization",
 78→								data: {
 79→									id: user.id,
 80→									name: `${user.name}'s Workspace`,
 81→									slug,
 82→									createdAt: new Date(),
 83→								},
 84→								forceAllowId: true,
 85→							});
 86→
 87→							if (org) {
 88→								await adapter.create({
 89→									model: "member",
 90→									data: {
 91→										organizationId: org.id,
 92→										userId: user.id,
 93→										role: "owner",
 94→										createdAt: new Date(),
 95→									},
 96→								});
 97→							}
 98→
 99→							if (config.slackWebhookUrl) {
100→								let githubHandle: string | null = null;
101→								const accounts = (await adapter.findMany({
102→									model: "account",
103→									where: [{ field: "userId", value: user.id }],
104→								})) as Array<{ providerId: string; accountId: string }>;
105→								const githubAccount = accounts.find(
106→									(a) => a.providerId === "github",
107→								);
108→								if (githubAccount) {
109→									githubHandle = await fetchGitHubHandle(
110→										githubAccount.accountId,
111→									);
112→								}
113→								await notifySignup(
114→									config.slackWebhookUrl,
115→									{ name: user.name, email: user.email },
116→									githubHandle,
117→								);
118→							}
119→						} catch (err) {
120→							logger.error(
121→								"Failed to create default organization for user {userId}: {error}",
122→								{ userId: user.id, error: err },
123→							);
124→						}
125→					},
126→				},
127→			},
128→		},
129→	});
130→}
