 62→const STATIC_DIR = join(
 63→	import.meta.dir,
 64→	"..",
 65→	process.env.STATIC_DIR ?? "public",
 66→);
 67→
 68→function corsHeaders(origin: string | null): Record<string, string> {
 69→	if (origin !== ALLOWED_ORIGIN) return {};
 70→	return {
 71→		"Access-Control-Allow-Origin": ALLOWED_ORIGIN,
 72→		"Access-Control-Allow-Credentials": "true",
 73→		"Access-Control-Allow-Methods": "GET, POST, PUT, DELETE, OPTIONS",
 74→		"Access-Control-Allow-Headers": "Content-Type, Authorization, X-API-Key",
 75→	};
 76→}
 77→
 78→const port = process.env.PORT ?? 4010;
 79→const MAX_REQUEST_BODY_BYTES = Number(
 80→	process.env.MAX_REQUEST_BODY_BYTES ?? 500 * 1024 * 1024, // 500 MB
 81→);
 82→
 83→const server = Bun.serve({
 84→	port,
 85→	async fetch(request) {
 86→		const origin = request.headers.get("Origin");
 87→		const cors = corsHeaders(origin);
 88→
 89→		if (request.method === "OPTIONS") {
 90→			return new Response(null, { status: 204, headers: cors });
 91→		}
 92→
 93→		const contentLength = request.headers.get("Content-Length");
 94→		if (contentLength && Number(contentLength) > MAX_REQUEST_BODY_BYTES) {
 95→			return new Response(
 96→				JSON.stringify({
 97→					error: `Request body too large. Maximum size is ${Math.round(MAX_REQUEST_BODY_BYTES / (1024 * 1024))} MB.`,
 98→				}),
 99→				{
100→					status: 413,
101→					headers: { ...cors, "Content-Type": "application/json" },
102→				},
103→			);
104→		}
105→
106→		const url = new URL(request.url);
107→
108→		// Health check for Fly.io (must be GET-accessible)
109→		if (url.pathname === "/health") {
110→			return Response.json({ status: "ok", timestamp: Date.now() });
111→		}
112→
113→		const requestId = crypto.randomUUID();
114→		const start = performance.now();
115→
116→		return withContext(
117→			{ requestId, method: request.method, path: url.pathname },
118→			async () => {
119→				const response = await handleRequest(request, url, cors);
120→				const duration = Math.round(performance.now() - start);
121→				logger.info("{method} {path} {status} {duration}ms", {
122→					method: request.method,
123→					path: url.pathname,
124→					status: response.status,
125→					duration,
126→				});
127→				return response;
128→			},
129→		);
130→	},
131→});
132→
133→async function handleRequest(
134→	request: Request,
135→	url: URL,
136→	cors: Record<string, string>,
137→): Promise<Response> {
138→	// Defense in depth: block Better Auth's built-in org deletion route.
139→	// Rudel has its own guarded deletion path via the RPC router.
140→	if (url.pathname === "/api/auth/organization/delete") {
141→		return new Response("Not Found", { status: 404, headers: cors });
142→	}
143→	if (url.pathname.startsWith("/api/auth")) {
144→		const response = await auth.handler(request);
145→		for (const [key, value] of Object.entries(cors)) {
146→			response.headers.set(key, value);
147→		}
148→		return response;
149→	}
150→
151→	const { matched, response } = await rpcHandler.handle(request, {
152→		prefix: "/rpc",
153→		context: await getContext(request),
154→	});
155→
156→	if (matched) {
157→		if (response.status >= 500) {
158→			const body = await response.clone().text();
159→			logger.error("RPC error on {path}: {status} {body}", {
160→				path: url.pathname,
161→				status: response.status,
162→				body,
163→			});
164→		}
165→		for (const [key, value] of Object.entries(cors)) {
166→			response.headers.set(key, value);
167→		}
168→		return response;
169→	}
170→
171→	// Static file serving (production: frontend assets)
172→	const filePath = join(STATIC_DIR, url.pathname);
173→	const file = Bun.file(filePath);
174→	if (await file.exists()) {
175→		return new Response(file);
176→	}
177→
178→	// SPA fallback: serve index.html for non-API routes
179→	const indexFile = Bun.file(join(STATIC_DIR, "index.html"));
180→	if (await indexFile.exists()) {
181→		return new Response(indexFile);
182→	}
183→
184→	// Dev mode: redirect to frontend dev server for non-API routes
185→	// (e.g., after OAuth callback redirects to APP_URL which has no SPA)
186→	if (ALLOWED_ORIGIN !== appURL) {
187→		return Response.redirect(
188→			`${ALLOWED_ORIGIN}${url.pathname}${url.search}`,
189→			302,
190→		);
191→	}
192→
193→	return new Response("Not found", { status: 404, headers: cors });
194→}
195→
196→async function getContext(request: Request) {
197→	const session = await auth.api.getSession({
198→		headers: request.headers,
199→	});
200→
201→	let apiKeyId: string | null = null;
202→	const apiKey =
203→		request.headers.get("x-api-key") ??
204→		request.headers.get("X-API-Key") ??
205→		null;
206→
207→	let apiKeyUser: AuthUser | null = null;
208→	if (apiKey) {
209→		try {
210→			const verification = await auth.api.verifyApiKey({
211→				body: {
212→					key: apiKey,
213→					permissions: { ingest: ["write"] },
214→				},
215→			});
216→
217→			if (verification.valid && verification.key) {
218→				const [foundUser] = await db
219→					.select({
220→						id: userTable.id,
221→						name: userTable.name,
222→						email: userTable.email,
223→						emailVerified: userTable.emailVerified,
224→						image: userTable.image,
225→						createdAt: userTable.createdAt,
226→						updatedAt: userTable.updatedAt,
227→					})
228→					.from(userTable)
229→					.where(eq(userTable.id, verification.key.referenceId))
230→					.limit(1);
231→
232→				if (foundUser) {
233→					apiKeyUser = foundUser as AuthUser;
234→					apiKeyId = verification.key.id;
235→				}
236→			}
237→		} catch {
238→			// Invalid API key is treated as unauthenticated for key-based auth.
239→		}
240→	}
241→
242→	return {
243→		user: session?.user ?? apiKeyUser ?? null,
244→		session: session?.session ?? null,
245→		apiKeyId,
246→	};
247→}
248→
